<script setup lang="ts">
const supabase = useSupabaseClient<any>()
const capability = ref('tools'), intent = ref('Use the best governed connected capability for this work'), loading = ref(false), plan = ref<any>(null), error = ref(''), outcomeMessage = ref('')
async function planRoute() { loading.value = true; error.value = ''; try { const { data: { session } } = await supabase.auth.getSession(); plan.value = await $fetch('/api/connectors/route-plan', { method: 'POST', body: { capability: capability.value, intent: intent.value }, headers: session?.access_token ? { authorization: `Bearer ${session.access_token}` } : {} }) } catch (e: any) { error.value = e?.data?.message || e?.message || 'No route could be explained.' } finally { loading.value = false } }
async function settle(succeeded: boolean) { const { data: { session } } = await supabase.auth.getSession(); await $fetch('/api/connectors/route-outcome', { method: 'POST', body: { receipt_id: plan.value.receipt.id, succeeded, quality: succeeded ? .9 : .2, policy_incidents: 0 }, headers: session?.access_token ? { authorization: `Bearer ${session.access_token}` } : {} }); outcomeMessage.value = 'Realized outcome recorded; future routes will incorporate this evidence.' }
</script>
<template><section class="mt-5 rounded-xl border bg-white p-4"><div class="text-[10px] font-semibold uppercase tracking-[.14em] text-blue-600">Explainable capability routing</div><h2 class="mt-1 text-sm font-semibold">Ask why a provider would be selected</h2><div class="mt-3 grid gap-2 md:grid-cols-[160px_1fr_auto]"><select v-model="capability" class="rounded-lg border px-3 py-2 text-xs"><option v-for="item in ['tools','models','repositories','search','messages','calendar','drive','pages','realtime']" :key="item">{{ item }}</option></select><input v-model="intent" class="rounded-lg border px-3 py-2 text-xs"><button :disabled="loading" class="rounded-lg bg-gray-900 px-4 py-2 text-xs text-white" @click="planRoute">{{ loading ? 'Ranking…' : 'Explain route' }}</button></div><p v-if="error" class="mt-2 text-xs text-red-600">{{ error }}</p><div v-if="plan?.selected" class="mt-4 grid gap-3 md:grid-cols-2"><article class="rounded-lg border border-emerald-200 bg-emerald-50 p-3"><div class="text-[10px] text-emerald-700">SELECTED · SCORE {{ plan.selected.score }}</div><h3 class="mt-1 text-sm font-semibold">{{ plan.selected.name }}</h3><p class="mt-1 text-xs text-gray-600">{{ plan.explanation.why_selected }}</p><ul class="mt-2 space-y-1 text-[10px] text-gray-500"><li v-for="line in plan.selected.explanation" :key="line">• {{ line }}</li></ul><div class="mt-3 flex gap-2"><button class="rounded border border-emerald-300 px-2 py-1 text-[10px]" @click="settle(true)">Record successful outcome</button><button class="rounded border px-2 py-1 text-[10px]" @click="settle(false)">Record poor outcome</button></div><p v-if="outcomeMessage" class="mt-2 text-[10px] text-emerald-700">{{ outcomeMessage }}</p></article><article class="rounded-lg border p-3"><div class="text-[10px] font-semibold text-gray-500">ALTERNATIVES</div><div v-for="item in plan.alternatives" :key="item.provider" class="mt-2 flex items-center justify-between text-xs"><span>{{ item.name }} <span v-if="!item.connected" class="text-amber-600">· connect first</span></span><span class="text-gray-400">{{ item.score }} · ${{ Number(item.estimated_cost_usd).toFixed(3) }}</span></div><p class="mt-3 text-[9px] text-gray-400">Receipt {{ plan.receipt?.id }} records policy version, permissions, alternatives, realized evidence, cost, and rationale.</p></article></div></section></template>
